CREATE TABLE IF NOT EXISTS t_p90995829_dmaxi_site_replica.users (id SERIAL PRIMARY KEY, name VARCHAR(200) NOT NULL, phone VARCHAR(20) NOT NULL UNIQUE, email VARCHAR(200), password_hash VARCHAR(255) NOT NULL, role VARCHAR(20) NOT NULL DEFAULT 'user', car_model VARCHAR(200), car_year VARCHAR(10), car_vin VARCHAR(50), bonus_points INTEGER NOT NULL DEFAULT 0, club_level VARCHAR(20) NOT NULL DEFAULT 'bronze', is_active BOOLEAN NOT NULL DEFAULT true, created_at TIMESTAMP NOT NULL DEFAULT NOW(), last_login TIMESTAMP);